import{_ as t,c as e,o as r,a2 as d}from"./chunks/framework.CL2JQ_2X.js";const p=JSON.parse('{"title":"RB-Y1","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"docs/introduction/index.md","filePath":"docs/introduction/index.md"}'),o={name:"docs/introduction/index.md"},a=d('<h1 id="rb-y1" tabindex="-1">RB-Y1 <a class="header-anchor" href="#rb-y1" aria-label="Permalink to &quot;RB-Y1&quot;">​</a></h1><p>Rainbow Robotics&#39; newly released Bimanual Mobile Manipulator RB-Y1 is equipped with both arms with 7 degrees of freedom per arm and a single leg with 6 degrees of freedom. This humanoid-shaped robot is mounted on a wheel-type high-speed mobile platform. By solving the limitations of one-armed collaborative robots and fixed industrial robots at once, repetitive and precise work is possible in various industrial sites.</p><p>Rainbow Robotics has core robot technology accumulated while developing humanoid robots. Based on this technology, we developed RB-Y1, a bimanual mobile manipulator that is in line with the generative AI era. We also plan to provide a development environment or sensors for various AI solutions.</p><h2 id="technical-specifications" tabindex="-1">Technical Specifications <a class="header-anchor" href="#technical-specifications" aria-label="Permalink to &quot;Technical Specifications&quot;">​</a></h2><h3 id="general-specifications" tabindex="-1">General Specifications <a class="header-anchor" href="#general-specifications" aria-label="Permalink to &quot;General Specifications&quot;">​</a></h3><table><thead><tr><th><strong>Attribute</strong></th><th><strong>Value</strong></th></tr></thead><tbody><tr><td><strong>Size</strong></td><td>600 x 690 x 1,400mm (W x D x H)</td></tr><tr><td><strong>Battery Capacity</strong></td><td>50V, 25Ah (1,270Wh)</td></tr><tr><td><strong>Degrees of Freedom</strong></td><td>See <a href="#degrees-of-freedom">Degrees of Freedom</a></td></tr><tr><td><strong>Weight</strong></td><td>See <a href="#weight">Weight</a></td></tr><tr><td><strong>Arm Payload</strong></td><td>3kg (per arm)</td></tr><tr><td><strong>Arm Reach</strong></td><td>600 mm (to wrist) + hand</td></tr><tr><td><strong>Joint Maximum Speed, Angle Range</strong></td><td>See <a href="#joint-maximum-speed-angle-range">Joint Maximum Speed, Angle Range</a></td></tr><tr><td><strong>Power Supply Voltage and Frequency</strong></td><td>48 VDC</td></tr><tr><td><strong>Ambient Operating Temperature</strong></td><td>40°C</td></tr><tr><td><strong>Safety Functions</strong></td><td>See <a href="#safety-functions">Safety Functions</a></td></tr><tr><td><strong>Arm Repeatability</strong></td><td>&lt; ±0.05 mm</td></tr><tr><td><strong>Exterior Materials</strong></td><td>Aluminum</td></tr><tr><td><strong>Mobile Base Speed</strong></td><td>1.5 m/s</td></tr></tbody></table><h3 id="degrees-of-freedom" tabindex="-1">Degrees of Freedom <a class="header-anchor" href="#degrees-of-freedom" aria-label="Permalink to &quot;Degrees of Freedom&quot;">​</a></h3><table><thead><tr><th><strong>PART</strong></th><th><strong># of DOF</strong></th></tr></thead><tbody><tr><td>Arm</td><td>7 DOF x 2</td></tr><tr><td>Leg</td><td>6 DOF</td></tr><tr><td>Gripper</td><td>1 DOF x 2</td></tr><tr><td>Wheel</td><td>1 DOF x 2</td></tr><tr><td><strong>Total</strong></td><td><strong>24 DOF</strong></td></tr></tbody></table><h3 id="weight" tabindex="-1">Weight <a class="header-anchor" href="#weight" aria-label="Permalink to &quot;Weight&quot;">​</a></h3><table><thead><tr><th><strong>PART</strong></th><th><strong>WEIGHT (kg)</strong></th></tr></thead><tbody><tr><td>Upper body</td><td>38kg (Arm 11kg x 2, Torso 16kg)</td></tr><tr><td>Lower body</td><td>42kg</td></tr><tr><td>Mobile</td><td>51kg</td></tr><tr><td><strong>Total</strong></td><td><strong>131kg</strong></td></tr></tbody></table><h3 id="joint-maximum-speed-angle-range" tabindex="-1">Joint Maximum Speed, Angle Range <a class="header-anchor" href="#joint-maximum-speed-angle-range" aria-label="Permalink to &quot;Joint Maximum Speed, Angle Range&quot;">​</a></h3><table><thead><tr><th><strong>Joint</strong></th><th><strong>Speed</strong></th><th><strong>Range</strong></th></tr></thead><tbody><tr><td>Ankle roll</td><td>120°/s</td><td>-20° ~ 20°</td></tr><tr><td>Ankle pitch</td><td>120°/s</td><td>-60° ~ 70°</td></tr><tr><td>Knee</td><td>180°/s</td><td>-140° ~ 45°</td></tr><tr><td>Hip pitch</td><td>180°/s</td><td>-45° ~ 90°</td></tr><tr><td>Hip roll</td><td>180°/s</td><td>-30° ~ 30°</td></tr><tr><td>Hip yaw</td><td>180°/s</td><td>-90° ~ 90°</td></tr><tr><td>Shoulder pitch</td><td>180°/s</td><td>-135° ~ 135°</td></tr><tr><td>Shoulder roll</td><td>180°/s</td><td>0° ~ 180°</td></tr><tr><td>Shoulder yaw</td><td>180°/s</td><td>-120° ~ 120°</td></tr><tr><td>Elbow pitch</td><td>180°/s</td><td>-150° ~ 0°</td></tr><tr><td>Wrist yaw1</td><td>360°/s</td><td>-360° ~ 360°</td></tr><tr><td>Wrist pitch</td><td>360°/s</td><td>-100° ~ 115°</td></tr><tr><td>Wrist yaw2</td><td>360°/s</td><td>-360° ~ 360°</td></tr></tbody></table><h3 id="safety-functions" tabindex="-1">Safety Functions <a class="header-anchor" href="#safety-functions" aria-label="Permalink to &quot;Safety Functions&quot;">​</a></h3><ul><li><strong>Low Level Controller (Motor Controller)</strong><ul><li>Pisition Reference Continuity Error</li><li>Position Tracking Error</li><li>Temperature Error</li><li>Overcurrent Error</li><li>Communication Error</li></ul></li><li><strong>High Level Controller</strong><ul><li>Current Limit</li></ul></li></ul>',14),n=[a];function i(s,l,h,g,c,m){return r(),e("div",null,n)}const f=t(o,[["render",i]]);export{p as __pageData,f as default};
